import React from 'react'
import useAuth from '../hooks/useAuth';

const setting = () => {
  const { user } = useAuth();

  return (
   <>
    <div className='setting'>
      <h1>Settings</h1>
      <p>Name: {user?.name}</p>
      <p>Email: {user?.email}</p>
    </div>
   </>
  )
}

export default setting
